import request from '@/utils/request'

export function getScoringInfo(voteId, groupId) {
  return request({
    url: `/judge/getScoringInfo?voteId=${voteId}&groupId=${groupId}`,
    method: 'get',
  })
}

export function getContestants(voteId) {
  return request({
    url: `/judge/contestants?voteId=${voteId}`,
    method: 'get',
  })
}

export function getScoreRuleList(voteId) {
  return request({
    url: `/judge/scoreRules?voteId=${voteId}`,
    method: 'get',
  })
}

export function getToken(data, voteId) {
  return request({
    url: `/judge/login`,
    method: 'post',
    data: data,
    root: true,
    judge: voteId,
  })
}

export function getUatedContestants(voteId) {
  return request({
    url: `/judge/unratedContestants`,
    method: 'get',
    judge: voteId,
  })
}

export function getRatedContestants(voteId) {
  return request({
    url: `/judge/ratedContestants`,
    method: 'get',
    judge: voteId,
  })
}

export function submitScore(voteId, data) {
  return request({
    url: `/judge/score`,
    method: 'post',
    data: data,
    judge: voteId,
  })
}

export function getJudgeScoreDetail(cid, voteId) {
  return request({
    url: `/judge/judgeScoreDetail?contestantId=${cid}`,
    method: 'get',
    judge: voteId,
  })
}

export function getRegisteredJudgesInfo(voteId) {
  return request({
    url: `/judge/registered-judges-info?voteId=${voteId}`,
    method: 'get',
  })
}

export function updateGroup(judgeId, groupId) {
  return request({
    url: `/judge/update-group?judgeId=${judgeId}&groupId=${groupId}`,
    method: 'post',
  })
}
