<template>
  <div>
    <span v-if="reScan">请重新扫描邀请码</span>
    <div v-else-if="data.voteInfo.id">
      <h2 class="text-bolder">{{ data.voteInfo.voteName }}</h2>
      <h3>主办单位：{{ data.voteInfo.organizer }}</h3>
      <h3>评委分组：{{ data.groupInfo.groupName }}</h3>
      <a-tag color="#108AF9" @click="route2contestantPreview">
        评分信息
      </a-tag>
      <a-tag color="#108AF9" @click="route2scoreRuleList">
        评分规则
      </a-tag>
      <a-tag color="#56BB51">
        进行中
      </a-tag>
      <!-- <a-button type="primary" style="width: 100%; height: 48px; margin-top: 16px; font-size: 24px; background-color: mediumseagreen; border-color: mediumseagreen;" @click="entry">
        查看分数
      </a-button> -->
      <a-button type="primary" style="width: 100%; height: 48px; margin-top: 16px; font-size: 24px;" @click="verifyToken">
        进入评分
      </a-button>
      <!-- <div style="width: 100%; height: 300px; background-color: aliceblue; margin-top: 20px; display: flex; justify-content: center; align-items: center;">此处加入广告</div> -->
      <van-dialog v-model="inputShow" title="设置评委信息" show-cancel-button :before-close="loginBeforeClose">
        <van-cell-group style="margin-top: 8px;">
          <van-field v-model="form.judgeName" label="" placeholder="请填写您的评委姓名/单位" />
        </van-cell-group>
      </van-dialog>
      <van-dialog v-model="judgeInfoShow" confirmButtonText="进入评分" show-cancel-button :before-close="judgeBeforeClose">
        <h2 style="text-align: center; margin-top: 20px;">欢迎您，{{ judgeInfo.name }}</h2>
      </van-dialog>
    </div>
  </div>
</template>
<script>
import { getScoringInfo, getToken } from '@/api/judge'
export default {
  data() {
    return {
      data: {
        voteInfo: {},
        groupInfo: {},
      },
      form: {
        judgeName: '',
      },
      judgeInfoShow: false,
      judgeInfo: {},
      inputShow: false,
      reScan: false,
    }
  },
  mounted() {
    if (!this.$route.query.groupId) {
      this.reScan = true
    } else {
      getScoringInfo(this.$route.query.voteId, this.$route.query.groupId).then(res => {
        this.data = res
      })
    }
  },
  methods: {
    entry() {
      this.$message.info('开发中')
    },
    verifyToken() {
      getToken({}, this.$route.query.voteId).then(res => {
          if (res.success) {
            this.judgeInfo = res
            this.judgeInfoShow = true
          } else {
            this.inputShow = true
          }
      }).catch(e => {
        console.log('fail', e)
      })
    },
    route2contestantPreview() {
      this.$router.push({
        name: 'judgeContestantPreview',
        query: {
          voteId: this.data.voteInfo.id,
        },
      })
    },
    route2scoreRuleList() {
      this.$router.push({
        name: 'judgeScoreRuleList',
        query: {
          voteId: this.data.voteInfo.id,
        },
      })
    },
    loginBeforeClose(action, done) {
      if (action === 'confirm') {
        if (!this.form.judgeName) {
          this.$message.error('姓名/单位名不能为空')
          done(false)
        } else {
          getToken({
            voteId: this.$route.query.voteId,
            groupId: this.$route.query.groupId,
            name: this.form.judgeName,
          }).then(res => {
            if (res.success) {
              this.$message.success(`欢迎登录，${res.name}`)
              this.route2contestantList()
              this.form.judgeName = ''
              localStorage.setItem(`JudgeToken-${this.$route.query.voteId}`, res.token)
              // setCookie('judge_token', res.token, 7)
              done()
            } else {
              this.$message.error(res.message)
              done(false)
            }
          })
        }
      } else {
        this.form.judgeName = ''
        done()
      }
    },
    judgeBeforeClose(action, done) {
      if (action === 'confirm') {
        this.route2contestantList()
        done()
      } else {
        done()
      }
    },
    route2contestantList() {
      this.$router.push({
        name: 'judgeContestantList',
        query: {
          voteId: this.data.voteInfo.id,
        },
      })
    },
  },
}
</script>
<style lang="less" scoped>
.ant-tag {
  font-size: 16px;
  line-height: 32px;
  border-radius: 20px;
  padding: 0 12px;
}

@media only screen and (max-width: 767px) {
  .text-bolder {
    text-shadow: 0.3px 0 0 currentColor, -0.3px 0 0 currentColor, 0 0.3px 0 currentColor, 0 -0.3px 0 currentColor;
  }
}
</style>
